// Export all optimization tests
module.exports = {
    optimizationTests,
    getAllOptimizationTests: () => {
        return [
            ...optimizationTests.fileLevelOptimization,
            ...optimizationTests.lineLevelOptimization,
            ...optimizationTests.semanticOptimization,
            ...optimizationTests.performanceOptimization,
            ...optimizationTests.securityOptimization,
            ...optimizationTests.architecturalOptimization
        ];
    },
    getOptimizationTestsByCategory: (category) => {
        const allTests = [
            ...optimizationTests.fileLevelOptimization,
            ...optimizationTests.lineLevelOptimization,
            ...optimizationTests.semanticOptimization,
            ...optimizationTests.performanceOptimization,
            ...optimizationTests.securityOptimization,
            ...optimizationTests.architecturalOptimization
        ];
        return allTests.filter(test => test.category === category);
    },
    getOptimizationTestsBySection: (section) => {
        switch(section) {
            case 'file': return optimizationTests.fileLevelOptimization;
            case 'line': return optimizationTests.lineLevelOptimization;
            case 'semantic': return optimizationTests.semanticOptimization;
            case 'performance': return optimizationTests.performanceOptimization;
            case 'security': return optimizationTests.securityOptimization;
            case 'architecture': return optimizationTests.architecturalOptimization;
            default: return [];
        }
    }
};